  let arcReverseEditor = null;

  function normalizeAngle(degrees) {
    return ((((degrees + 180) % 360) + 360) % 360) - 180;
  }

  function regularPolygonVertices(sides, sideLength, startAngleDegrees) {
    const radius = sideLength / (2 * Math.sin(Math.PI / sides));
    const vertices = [];

    for (let i = 0; i < sides; i += 1) {
      const angle = (startAngleDegrees + 360 * i / sides) * Math.PI / 180;
      vertices.push({
        x: radius * Math.cos(angle),
        y: radius * Math.sin(angle)
      });
    }

    return vertices;
  }

  function pointsFromVertices(vertices) {
    return vertices
      .map(vertex => `${Number(vertex.x.toFixed(2))},${Number(vertex.y.toFixed(2))}`)
      .join(" ");
  }

  function makeRegularTile(label, color, sides, startAngleDegrees) {
    const vertices = regularPolygonVertices(sides, SIDE_LENGTH, startAngleDegrees);
    const radius = SIDE_LENGTH / (2 * Math.sin(Math.PI / sides));

    return {
      label,
      color,
      sides,
      sideLength: SIDE_LENGTH,
      radius,
      startAngleDegrees,
      vertices,
      points: pointsFromVertices(vertices)
    };
  }

  function bubbleTilePath(vertices, bites) {
    const commands = [];

    commands.push(`M ${vertices[0].x.toFixed(3)} ${vertices[0].y.toFixed(3)}`);

    for (let i = 0; i < vertices.length; i += 1) {
      const start = vertices[i];
      const next = vertices[(i + 1) % vertices.length];
      const isBite = bites[i] === 1;

      /*
        Each side is drawn as the 60-degree circular arc on its own chord.
        For ordinary bubble tiles the chord length is SIDE_LENGTH. For converted
        polygons/monotiles, using the actual chord length keeps long or unusual
        edges valid instead of asking SVG to draw an impossible radius.
      */
      const arcRadius = Math.hypot(next.x - start.x, next.y - start.y) || SIDE_LENGTH;
      const sweep = isBite ? 0 : 1;

      commands.push(
        `A ${arcRadius.toFixed(3)} ${arcRadius.toFixed(3)} 0 0 ${sweep} ${next.x.toFixed(3)} ${next.y.toFixed(3)}`
      );
    }

    commands.push("Z");
    return commands.join(" ");
  }

  const PUZZLE_EDGE_CUBICS = [
    [[0.0000, 0.0000], [0.3110, 0.0428], [0.3458, 0.0376]],
    [[0.3806, 0.0325], [0.4120, 0.0177], [0.4216, -0.0094]],
    [[0.4312, -0.0364], [0.3886, -0.0974], [0.3900, -0.1626]],
    [[0.3914, -0.2278], [0.4301, -0.2418], [0.4437, -0.2514]],
    [[0.4573, -0.2610], [0.5000, -0.2608], [0.5000, -0.2608]],
    [[0.5000, -0.2608], [0.5427, -0.2610], [0.5563, -0.2514]],
    [[0.5699, -0.2418], [0.6086, -0.2278], [0.6100, -0.1626]],
    [[0.6114, -0.0974], [0.5688, -0.0364], [0.5784, -0.0094]],
    [[0.5880, 0.0177], [0.6194, 0.0325], [0.6542, 0.0377]],
    [[0.6890, 0.0428], [1.0000, 0.0000], [1.0000, 0.0000]]
  ];

  const PUZZLE_PROFILE_DEPTH = SIDE_LENGTH * 0.78;

  /*
    Compact Spike Bubble Style constants.
    These values are intentionally small. Do not revert to the old oversized
    0.42 * SIDE_LENGTH spike depth; that creates the “big spikes” regression.
  */
  const SPIKE_PROFILE_DEPTH = SIDE_LENGTH * 0.18;
  const SPIKE_PROFILE_MAX_SEGMENT_FRACTION = 0.22;
  const SPIKE_PROFILE_SHOULDER_IN = 0.38;
  const SPIKE_PROFILE_SHOULDER_OUT = 0.62;

  /*
    Square Tooth Bubble Style constants. This profile is a rectangular
    square-wave step: ___|---|___ . Keep these compact so 60-degree corners do
    not self-intersect. The saved internal value remains "zigzag" for backward
    compatibility with the first test build of this style.
  */
  const ZIGZAG_PROFILE_DEPTH = SIDE_LENGTH * 0.14;
  const ZIGZAG_PROFILE_MAX_SEGMENT_FRACTION = 0.18;
  const ZIGZAG_PROFILE_SHOULDER_IN = 0.40;
  const ZIGZAG_PROFILE_SHOULDER_OUT = 0.60;

  function polygonSignedArea(vertices) {
    if (!Array.isArray(vertices) || vertices.length < 3) return 1;
    let area = 0;
    for (let i = 0; i < vertices.length; i += 1) {
      const current = vertices[i];
      const next = vertices[(i + 1) % vertices.length];
      area += current.x * next.y - next.x * current.y;
    }
    return area / 2;
  }

  function edgeOutwardNormalForVertices(vertices, edgeIndex) {
    const start = vertices[edgeIndex];
    const end = vertices[(edgeIndex + 1) % vertices.length];
    const dx = end.x - start.x;
    const dy = end.y - start.y;
    const length = Math.hypot(dx, dy) || 1;

    // The app's built-in polygons use positive signed area in SVG coordinates.
    // For those paths, the outward side of an edge is the right-hand normal.
    if (polygonSignedArea(vertices) >= 0) {
      return { x: dy / length, y: -dx / length };
    }

    return { x: -dy / length, y: dx / length };
  }

  function edgeOutwardNormal(start, end) {
    const dx = end.x - start.x;
    const dy = end.y - start.y;
    const length = Math.hypot(dx, dy) || 1;
    return { x: dy / length, y: -dx / length };
  }

  function buildScaledPuzzleProfilePath(start, end, options = {}) {
    const segmentStart = typeof options.segmentStart === "number" ? options.segmentStart : 0;
    const segmentEnd = typeof options.segmentEnd === "number" ? options.segmentEnd : 1;
    const amplitude = typeof options.amplitude === "number" ? options.amplitude : SIDE_LENGTH;
    const sign = options.sign === -1 ? -1 : 1;
    const outward = options.outward || edgeOutwardNormal(start, end);
    const dx = end.x - start.x;
    const dy = end.y - start.y;
    const span = segmentEnd - segmentStart;
    const pieces = [`M ${ (start.x + dx * segmentStart).toFixed(3)} ${(start.y + dy * segmentStart).toFixed(3)}`];

    function profilePoint(pair) {
      const t = segmentStart + pair[0] * span;
      const normal = pair[1] * amplitude * sign;
      return {
        x: start.x + dx * t + outward.x * normal,
        y: start.y + dy * t + outward.y * normal
      };
    }

    PUZZLE_EDGE_CUBICS.forEach(cubic => {
      const c1 = profilePoint(cubic[0]);
      const c2 = profilePoint(cubic[1]);
      const p = profilePoint(cubic[2]);
      pieces.push(`C ${c1.x.toFixed(3)} ${c1.y.toFixed(3)}, ${c2.x.toFixed(3)} ${c2.y.toFixed(3)}, ${p.x.toFixed(3)} ${p.y.toFixed(3)}`);
    });

    return pieces.join(" ");
  }

  function puzzleTilePath(vertices, bites) {
    const commands = [];

    /*
      Jigsaw edge profile adapted from John's Inkscape SVG edge.
      The normalized coordinates below trace one exact horizontal socket
      profile; tab/blank is generated by flipping the normal direction.
    */

    commands.push(`M ${vertices[0].x.toFixed(3)} ${vertices[0].y.toFixed(3)}`);

    for (let i = 0; i < vertices.length; i += 1) {
      const start = vertices[i];
      const end = vertices[(i + 1) % vertices.length];
      const outward = edgeOutwardNormalForVertices(vertices, i);

      // Original profile is a socket; flip it for a tab.
      const sign = bites[i] === 1 ? 1 : -1;
      const amplitude = PUZZLE_PROFILE_DEPTH;
      const profiledPath = buildScaledPuzzleProfilePath(start, end, {
        segmentStart: 0,
        segmentEnd: 1,
        amplitude,
        sign,
        outward
      });

      commands.push(profiledPath.replace(/^M [^ ]+ [^ ]+\s*/, ""));
    }

    commands.push("Z");
    return commands.join(" ");
  }

  function makePuzzleTile(bubbleLabel, color, sides, startAngleDegrees, bites) {
    const base = makeRegularTile("", color, sides, startAngleDegrees);

    return {
      ...base,
      bubbleLabel,
      bites,
      path: puzzleTilePath(base.vertices, bites),
      isPuzzleTile: true
    };
  }



  function makeChevronPuzzleTile(bubbleLabel, color, sides, startAngleDegrees, flipIndices, bites, defaultRotation = 0) {
    const base = makeRegularTile('', color, sides, startAngleDegrees);
    const flipSet = new Set(flipIndices || []);
    const depth = sides === 6 ? SIDE_LENGTH * 0.58 : SIDE_LENGTH * 0.46;
    const rawVertices = [];

    for (let i = 0; i < sides; i += 1) {
      const current = base.vertices[i];
      const next = base.vertices[(i + 1) % sides];
      rawVertices.push(current);

      if (flipSet.has(i)) {
        const mid = {
          x: (current.x + next.x) / 2,
          y: (current.y + next.y) / 2
        };
        const length = Math.hypot(mid.x, mid.y) || 1;
        rawVertices.push({
          x: mid.x - (mid.x / length) * depth,
          y: mid.y - (mid.y / length) * depth
        });
      }
    }

    const tile = makeCustomPolygonTile(bubbleLabel, color, rawVertices);
    tile.defaultRotation = defaultRotation;
    tile.isChevronVariant = true;
    tile.originalSides = sides;
    tile.originalBites = bites || [];
    return tile;
  }

  function makeArcBubbleTile(bubbleLabel, color, sides, startAngleDegrees, bites) {
    const base = makeRegularTile("", color, sides, startAngleDegrees);

    return {
      ...base,
      bubbleLabel,
      bites,
      path: bubbleTilePath(base.vertices, bites)
    };
  }

  function makeBubbleTile(bubbleLabel, color, bites) {
    return {
      ...makeArcBubbleTile(bubbleLabel, color, 6, -90, bites),
      defaultRotation: 30
    };
  }


  function makeBubbleTileFromVertices(bubbleLabel, color, rawVertices, bites, defaultRotation = 0) {
    const vertices = centeredVertices(rawVertices);

    return {
      label: "",
      bubbleLabel,
      color,
      sides: vertices.length,
      sideLength: SIDE_LENGTH,
      radius: radiusFromVertices(vertices),
      startAngleDegrees: 0,
      vertices,
      bites,
      path: bubbleTilePath(vertices, bites),
      defaultRotation
    };
  }

  function makeCustomPuzzlePolygonTile(bubbleLabel, color, rawVertices, bites, defaultRotation = 0) {
    const vertices = centeredVertices(rawVertices);

    return {
      label: "",
      bubbleLabel,
      color,
      sides: vertices.length,
      sideLength: SIDE_LENGTH,
      radius: radiusFromVertices(vertices),
      startAngleDegrees: 0,
      vertices,
      bites,
      path: puzzleTilePath(vertices, bites),
      isPuzzleTile: true,
      defaultRotation
    };
  }

  function lerpPoint(a, b, t) {
    return {
      x: a.x + (b.x - a.x) * t,
      y: a.y + (b.y - a.y) * t
    };
  }

  function softBubbleTilePath(vertices, bites) {
    const arcRadius = SIDE_LENGTH;
    const commands = [];
    const allPlain = !bites || bites.every(value => value !== 1);

    if (allPlain) return bubbleTilePath(vertices, [0, 0, 0, 0, 0, 0]);

    commands.push(`M ${vertices[0].x.toFixed(3)} ${vertices[0].y.toFixed(3)}`);

    for (let i = 0; i < vertices.length; i += 1) {
      const start = vertices[i];
      const next = vertices[(i + 1) % vertices.length];

      if (bites[i] === 1) {
        const midpoint = {
          x: (start.x + next.x) / 2,
          y: (start.y + next.y) / 2
        };
        const length = Math.hypot(midpoint.x, midpoint.y) || 1;
        const outward = {
          x: midpoint.x / length,
          y: midpoint.y / length
        };
        const apex = {
          x: midpoint.x + outward.x * SIDE_LENGTH * Math.sqrt(3) / 2,
          y: midpoint.y + outward.y * SIDE_LENGTH * Math.sqrt(3) / 2
        };

        // Boundary of an H0 circle with a T3 triangular bubble tile attached on this side:
        // the shared edge disappears; the two remaining T3 arcs meet at a sharp point.
        commands.push(`A ${arcRadius} ${arcRadius} 0 0 0 ${apex.x.toFixed(3)} ${apex.y.toFixed(3)}`);
        commands.push(`A ${arcRadius} ${arcRadius} 0 0 0 ${next.x.toFixed(3)} ${next.y.toFixed(3)}`);
      } else {
        commands.push(`A ${arcRadius} ${arcRadius} 0 0 1 ${next.x.toFixed(3)} ${next.y.toFixed(3)}`);
      }
    }

    commands.push('Z');
    return commands.join(' ');
  }


  function makeSoftBubbleTile(bubbleLabel, color, bites) {
    const base = makeRegularTile('', color, 6, -90);
    const allPlain = !bites || bites.every(value => value !== 1);
    const normalizedBites = (Array.isArray(bites) ? bites : [0, 0, 0, 0, 0, 0]).map(value => value === 1 ? 1 : 0);
    const snapEdgesLocal = [];

    base.vertices.forEach((vertex, index) => {
      const next = base.vertices[(index + 1) % base.vertices.length];

      if (normalizedBites[index] === 1) {
        const mid = midpoint(vertex, next);
        const length = Math.hypot(mid.x, mid.y) || 1;
        const outward = { x: mid.x / length, y: mid.y / length };
        const apex = {
          x: mid.x + outward.x * SIDE_LENGTH * Math.sqrt(3) / 2,
          y: mid.y + outward.y * SIDE_LENGTH * Math.sqrt(3) / 2
        };

        // These are the two exposed sides of the T3 protrusion.  They are the
        // only snapping edges for a protrusion; the hidden base chord is not
        // a real exposed boundary and should not be used for snapping.
        snapEdgesLocal.push({
          start: vertex,
          end: apex,
          index: index * 2,
          bite: 1,
          isBubbleEdge: true,
          isSoftEdge: true,
          softKind: 'protrusion'
        });
        snapEdgesLocal.push({
          start: apex,
          end: next,
          index: index * 2 + 1,
          bite: 1,
          isBubbleEdge: true,
          isSoftEdge: true,
          softKind: 'protrusion'
        });
      } else {
        // Exposed circular side of the central H0 circle.
        snapEdgesLocal.push({
          start: vertex,
          end: next,
          index,
          bite: 0,
          isBubbleEdge: true,
          isSoftEdge: true,
          softKind: 'circle'
        });
      }
    });

    return {
      ...base,
      bubbleLabel,
      bites: normalizedBites,
      radius: allPlain ? SIDE_LENGTH : SIDE_LENGTH * 1.9,
      path: softBubbleTilePath(base.vertices, normalizedBites),
      defaultRotation: 30,
      snapRotationTolerance: 181,
      snapEdgesLocal,
      isSoftTile: true
    };
  }

  function makeRhombicBubbleTile(bubbleLabel, color, bites) {
    const side = SIDE_LENGTH;
    const angle = 60 * Math.PI / 180;
    const rawVertices = [
      { x: 0, y: 0 },
      { x: side, y: 0 },
      { x: side + side * Math.cos(angle), y: side * Math.sin(angle) },
      { x: side * Math.cos(angle), y: side * Math.sin(angle) }
    ];

    return makeBubbleTileFromVertices(bubbleLabel, color, rawVertices, bites, 0);
  }

    function makeArcLensTile(bubbleLabel, color) {
    const half = SIDE_LENGTH / 2;
    const path = `M ${-half},0 A ${SIDE_LENGTH} ${SIDE_LENGTH} 0 0 1 ${half},0 A ${SIDE_LENGTH} ${SIDE_LENGTH} 0 0 1 ${-half},0 Z`;
    const tile = makeCompoundPathTile(bubbleLabel, color, path, [
      { x: -half, y: 0 },
      { x: half, y: 0 }
    ], SIDE_LENGTH / Math.sqrt(3));
    tile.sides = 6;
    tile.bites = [0, 1];
    tile.isArcLensTile = true;
    tile.defaultRotation = 0;
    tile.snapRotationTolerance = 181;
    tile.snapEdgesLocal = [
      { start: { x: -half, y: 0 }, end: { x: half, y: 0 }, index: 0, bite: 0, isBubbleEdge: true },
      { start: { x: half, y: 0 }, end: { x: -half, y: 0 }, index: 1, bite: 0, isBubbleEdge: true },
      { start: { x: -half, y: 0 }, end: { x: half, y: 0 }, index: 2, bite: 1, isBubbleEdge: true },
      { start: { x: half, y: 0 }, end: { x: -half, y: 0 }, index: 3, bite: 1, isBubbleEdge: true }
    ];
    return tile;
  }

  function roundedRectanglePath(width, height, radius) {
    const x = -width / 2;
    const y = -height / 2;
    const right = width / 2;
    const bottom = height / 2;

    return [
      `M ${x + radius} ${y}`,
      `H ${right - radius}`,
      `Q ${right} ${y} ${right} ${y + radius}`,
      `V ${bottom - radius}`,
      `Q ${right} ${bottom} ${right - radius} ${bottom}`,
      `H ${x + radius}`,
      `Q ${x} ${bottom} ${x} ${bottom - radius}`,
      `V ${y + radius}`,
      `Q ${x} ${y} ${x + radius} ${y}`,
      "Z"
    ].join(" ");
  }

  function transformLocalPoint(point, translation, rotation = 0) {
    const rotated = rotatePoint(point, rotation);

    return {
      x: rotated.x + translation.x,
      y: rotated.y + translation.y
    };
  }

  function transformedBubblePath(tileType, x, y, rotation = 0) {
    const definition = tileDefinitions[tileType];
    const vertices = definition.vertices.map(vertex => transformLocalPoint(vertex, { x, y }, rotation));
    const bites = definition.bites || [];
    const arcRadius = SIDE_LENGTH;
    const commands = [];

    commands.push(`M ${vertices[0].x.toFixed(3)} ${vertices[0].y.toFixed(3)}`);

    for (let i = 0; i < vertices.length; i += 1) {
      const next = vertices[(i + 1) % vertices.length];
      const sweep = bites[i] === 1 ? 0 : 1;

      commands.push(`A ${arcRadius} ${arcRadius} 0 0 ${sweep} ${next.x.toFixed(3)} ${next.y.toFixed(3)}`);
    }

    commands.push("Z");
    return commands.join(" ");
  }

  function transformedSocketEdges(tileType, x, y, rotation = 0) {
    const definition = tileDefinitions[tileType];

    if (!definition || !Array.isArray(definition.vertices)) return [];

    return definition.vertices.map((vertex, index) => {
      const next = definition.vertices[(index + 1) % definition.vertices.length];

      return {
        start: transformLocalPoint(vertex, { x, y }, rotation),
        end: transformLocalPoint(next, { x, y }, rotation),
        index,
        bite: definition.bites ? definition.bites[index] : null,
        isBubbleEdge: Array.isArray(definition.bites),
        isFrameSocket: true
      };
    });
  }

  function centeredVertices(vertices) {
    const center = vertices.reduce((sum, vertex) => ({
      x: sum.x + vertex.x,
      y: sum.y + vertex.y
    }), { x: 0, y: 0 });

    center.x /= vertices.length;
    center.y /= vertices.length;

    return vertices.map(vertex => ({
      x: vertex.x - center.x,
      y: vertex.y - center.y
    }));
  }

  function radiusFromVertices(vertices) {
    return Math.max(...vertices.map(vertex => Math.hypot(vertex.x, vertex.y)));
  }

  function makeCustomPolygonTile(label, color, rawVertices) {
    const vertices = centeredVertices(rawVertices);

    return {
      label: "",
      bubbleLabel: label,
      color,
      sides: vertices.length,
      sideLength: SIDE_LENGTH,
      radius: radiusFromVertices(vertices),
      startAngleDegrees: 0,
      vertices,
      points: pointsFromVertices(vertices)
    };
  }

  function makeCompoundPathTile(label, color, path, rawVertices, radiusOverride = null) {
    const vertices = centeredVertices(rawVertices);
    const rawCenter = rawVertices.reduce((sum, vertex) => ({ x: sum.x + vertex.x, y: sum.y + vertex.y }), { x: 0, y: 0 });
    rawCenter.x /= rawVertices.length;
    rawCenter.y /= rawVertices.length;

    const centeredPath = path.replace(/(-?\d+(?:\.\d+)?),(-?\d+(?:\.\d+)?)/g, (_match, xValue, yValue) => {
      const x = Number(xValue) - rawCenter.x;
      const y = Number(yValue) - rawCenter.y;
      return x.toFixed(3) + "," + y.toFixed(3);
    });

    return {
      label: "",
      bubbleLabel: label,
      color,
      sides: vertices.length,
      sideLength: SIDE_LENGTH,
      radius: radiusOverride || radiusFromVertices(vertices),
      startAngleDegrees: 0,
      vertices,
      path: centeredPath
    };
  }

  function makePolyominoTile(label, color, cells) {
    const size = 44;
    const pathParts = [];

    cells.forEach(cell => {
      const x = cell[0] * size;
      const y = cell[1] * size;
      pathParts.push(`M ${x},${y} H ${x + size} V ${y + size} H ${x} Z`);
    });

    const minX = Math.min(...cells.map(cell => cell[0] * size));
    const maxX = Math.max(...cells.map(cell => (cell[0] + 1) * size));
    const minY = Math.min(...cells.map(cell => cell[1] * size));
    const maxY = Math.max(...cells.map(cell => (cell[1] + 1) * size));

    const tile = makeCompoundPathTile(label, color, pathParts.join(" "), [
      { x: minX, y: minY }, { x: maxX, y: minY }, { x: maxX, y: maxY }, { x: minX, y: maxY }
    ]);
    tile.isPolyomino = true;
    return tile;
  }

  function makeRhombTile(label, color, acuteAngleDegrees) {
    const side = SIDE_LENGTH;
    const angle = acuteAngleDegrees * Math.PI / 180;

    const rawVertices = [
      { x: 0, y: 0 },
      { x: side, y: 0 },
      { x: side + side * Math.cos(angle), y: side * Math.sin(angle) },
      { x: side * Math.cos(angle), y: side * Math.sin(angle) }
    ];

    return makeCustomPolygonTile(label, color, rawVertices);
  }

  function makeRegularStellationTile(label, color, pointCount) {
    const halfStep = Math.PI / pointCount;
    const innerRatio = Math.cos(2 * Math.PI / pointCount) / Math.cos(Math.PI / pointCount);
    const unitOuterSegment = Math.sqrt(1 + innerRatio * innerRatio - 2 * innerRatio * Math.cos(halfStep));
    const outerRadius = SIDE_LENGTH / unitOuterSegment;
    const innerRadius = outerRadius * innerRatio;
    const rawVertices = [];

    for (let index = 0; index < pointCount * 2; index += 1) {
      const radius = index % 2 === 0 ? outerRadius : innerRadius;
      const angle = -Math.PI / 2 + index * halfStep;
      rawVertices.push({
        x: radius * Math.cos(angle),
        y: radius * Math.sin(angle)
      });
    }

    const tile = makeCustomPolygonTile(label, color, rawVertices);
    tile.defaultRotation = 0;
    tile.snapRotationTolerance = 181;
    tile.isRegularStellation = true;
    return tile;
  }

  function makeUnitIsoscelesRightTriangleTile() {
    const side = SIDE_LENGTH;
    const tile = makeCustomPolygonTile("45-45-90 Triangle", "#65b96e", [
      { x: 0, y: 0 },
      { x: side, y: 0 },
      { x: 0, y: side }
    ]);
    tile.defaultRotation = 0;
    tile.snapRotationTolerance = 181;
    return tile;
  }

  function makeTangramParallelogramTile() {
    const side = SIDE_LENGTH;
    const tile = makeCustomPolygonTile("Tangram Parallelogram", "#4aa6a6", [
      { x: 0, y: 0 },
      { x: side, y: 0 },
      { x: 2 * side, y: side },
      { x: side, y: side }
    ]);
    tile.defaultRotation = 0;
    tile.snapRotationTolerance = 181;
    return tile;
  }

  function snapSegmentsBetween(start, end, segments, startingIndex = 0) {
    const snapEdges = [];

    for (let segment = 0; segment < segments; segment += 1) {
      const t0 = segment / segments;
      const t1 = (segment + 1) / segments;
      snapEdges.push({
        start: lerpPoint(start, end, t0),
        end: lerpPoint(start, end, t1),
        index: startingIndex + segment,
        bite: null,
        isBubbleEdge: false,
        isFrameSocket: true,
        isUnitSnapEdge: true
      });
    }

    return snapEdges;
  }

  function assignUnitSnapEdges(tile, vertices, segmentCounts) {
    const snapEdges = [];
    let index = 0;

    vertices.forEach((vertex, edgeIndex) => {
      const next = vertices[(edgeIndex + 1) % vertices.length];
      const count = segmentCounts[edgeIndex] || 1;
      snapEdges.push(...snapSegmentsBetween(vertex, next, count, index));
      index += count;
    });

    tile.snapEdgesLocal = snapEdges;
    tile.snapRotationTolerance = 181;
    return tile;
  }

  function angularDistance(a, b) {
    return Math.atan2(Math.sin(a - b), Math.cos(a - b));
  }

  function smoothClosedPathFromPoints(points, tension = 0.22) {
    if (!points.length) return "";

    const commands = [`M ${points[0].x.toFixed(3)} ${points[0].y.toFixed(3)}`];
    const n = points.length;

    for (let i = 0; i < n; i += 1) {
      const p0 = points[(i - 1 + n) % n];
      const p1 = points[i];
      const p2 = points[(i + 1) % n];
      const p3 = points[(i + 2) % n];
      const c1 = {
        x: p1.x + (p2.x - p0.x) * tension,
        y: p1.y + (p2.y - p0.y) * tension
      };
      const c2 = {
        x: p2.x - (p3.x - p1.x) * tension,
        y: p2.y - (p3.y - p1.y) * tension
      };
      commands.push(`C ${c1.x.toFixed(3)} ${c1.y.toFixed(3)}, ${c2.x.toFixed(3)} ${c2.y.toFixed(3)}, ${p2.x.toFixed(3)} ${p2.y.toFixed(3)}`);
    }

    commands.push("Z");
    return commands.join(" ");
  }

    function makeUnitRectangleTile(label, color) {
    const s = SIDE_LENGTH;
    const vertices = [
      { x: -s, y: -s / 2 },
      { x: s, y: -s / 2 },
      { x: s, y: s / 2 },
      { x: -s, y: s / 2 }
    ];
    const tile = makeCustomPolygonTile(label, color, vertices);
    return assignUnitSnapEdges(tile, tile.vertices, [2, 1, 2, 1]);
  }


    function makeUnitTrapezoidTile(label, color) {
    const s = SIDE_LENGTH;
    const height = Math.sqrt(3) * s / 2;
    const vertices = [
      { x: -s, y: height / 2 },
      { x: s, y: height / 2 },
      { x: s / 2, y: -height / 2 },
      { x: -s / 2, y: -height / 2 }
    ];
    const tile = makeCustomPolygonTile(label, color, vertices);
    return assignUnitSnapEdges(tile, tile.vertices, [2, 1, 1, 1]);
  }


    function makePacmanHexagonTile(label, color) {
    const vertices = regularPolygonVertices(6, SIDE_LENGTH, -90);
    const innerMouth = {
      x: 0,
      y: 0
    };
    const rawVertices = [
      vertices[0],
      innerMouth,
      vertices[2],
      vertices[3],
      vertices[4],
      vertices[5]
    ];
    const tile = makeCustomPolygonTile(label, color, rawVertices);
    tile.defaultRotation = 0;
    tile.snapRotationTolerance = 181;
    return assignUnitSnapEdges(tile, tile.vertices, segmentCountsFromVertices(tile.vertices));
  }

  function makePacmanPentagonTile(label, color) {
    const vertices = regularPolygonVertices(5, SIDE_LENGTH, -90);
    const reflectedTop = reflectPointAcrossLine(vertices[0], vertices[4], vertices[1]);
    const rawVertices = [
      vertices[3],
      vertices[2],
      vertices[1],
      reflectedTop,
      vertices[4]
    ];
    const tile = makeCustomPolygonTile(label, color, rawVertices);
    tile.defaultRotation = 0;
    tile.snapRotationTolerance = 181;
    tile.snapDistanceMultiplier = 2.2;
    return assignUnitSnapEdges(tile, tile.vertices, new Array(tile.vertices.length).fill(1));
  }

  function makeSquiggleOctagonTile(label, color) {
    const rawVertices = equilateralPolygonFromInteriorAngles([120, 120, 60, 240, 120, 120, 60, 240], SIDE_LENGTH, 0);
    const tile = makeCustomPolygonTile(label, color, rawVertices);
    tile.defaultRotation = 0;
    tile.snapRotationTolerance = 181;
    return assignUnitSnapEdges(tile, tile.vertices, new Array(tile.vertices.length).fill(1));
  }

  function reflectPointAcrossLine(point, a, b) {
    const dx = b.x - a.x;
    const dy = b.y - a.y;
    const lengthSquared = dx * dx + dy * dy || 1;
    const t = ((point.x - a.x) * dx + (point.y - a.y) * dy) / lengthSquared;
    const foot = {
      x: a.x + t * dx,
      y: a.y + t * dy
    };

    return {
      x: 2 * foot.x - point.x,
      y: 2 * foot.y - point.y
    };
  }

  function makePacmanOctagonTile(label, color, flippedVertexIndices) {
    const vertices = regularPolygonVertices(8, SIDE_LENGTH, -112.5);
    const flipSet = new Set(flippedVertexIndices || []);
    const rawVertices = vertices.map((vertex, index) => {
      if (!flipSet.has(index)) return vertex;
      const previous = vertices[(index - 1 + vertices.length) % vertices.length];
      const next = vertices[(index + 1) % vertices.length];
      return reflectPointAcrossLine(vertex, previous, next);
    });
    const tile = makeCustomPolygonTile(label, color, rawVertices);
    tile.defaultRotation = 0;
    tile.snapRotationTolerance = 181;
    tile.snapDistanceMultiplier = 2.2;
    return assignUnitSnapEdges(tile, tile.vertices, new Array(tile.vertices.length).fill(1));
  }


  function equilateralPolygonFromInteriorAngles(interiorAngles, sideLength, startAngleDegrees = 0) {
    let angle = startAngleDegrees * Math.PI / 180;
    const points = [{ x: 0, y: 0 }];
    let current = { x: 0, y: 0 };

    interiorAngles.forEach(interiorAngle => {
      current = {
        x: current.x + sideLength * Math.cos(angle),
        y: current.y + sideLength * Math.sin(angle)
      };
      points.push(current);
      angle += (180 - interiorAngle) * Math.PI / 180;
    });

    points.pop();
    return points;
  }

  function makePacmanOctagonThreeEdgeTile(label, color) {
    // Equilateral nonconvex octagon from John's annotated reference:
    // side lengths all 1, interior angles 45, 135, 135, 135, 135, 45, 225, 225.
    // The 0-degree starting edge produces the intended right-facing C/mouth shape.
    const rawVertices = equilateralPolygonFromInteriorAngles([45, 135, 135, 135, 135, 45, 225, 225], SIDE_LENGTH, 0);
    const tile = makeCustomPolygonTile(label, color, rawVertices);
    tile.defaultRotation = 0;
    tile.snapRotationTolerance = 181;
    tile.snapDistanceMultiplier = 2.2;
    return assignUnitSnapEdges(tile, tile.vertices, new Array(tile.vertices.length).fill(1));
  }


  function makeMonotileTile(label, color, a, b, curve, scaleMultiplier = 1) {
    /*
      Hat/Turtle/Spectre family construction based on Christian Lawson-Perfect's
      monotile.js generator. The 14 edge vectors use parameters a and b; curve = 0
      gives the straight-edged polygonal members, and curve > 0 curves each edge.
    */
    const scale = SIDE_LENGTH * scaleMultiplier;
    const c = Math.cos(Math.PI / 3);
    const s = Math.sin(Math.PI / 3);

    const moves = [
      [c * b, s * b],
      [b, 0],
      [0, a],
      [s * a, c * a],
      [c * b, -s * b],
      [-c * b, -s * b],
      [s * a, -c * a],
      [0, -a],
      [0, -a],
      [-s * a, -c * a],
      [-c * b, s * b],
      [-b, 0],
      [0, a],
      [-s * a, c * a]
    ].map(move => [move[0] * scale, move[1] * scale]);

    let x = 0;
    let y = 0;
    const rawVertices = [{ x, y }];
    const segments = [];

    function twiddle(dx, dy) {
      const nx = dy;
      const ny = -dx;

      return {
        c1: { x: -curve * nx + dx / 2, y: -curve * ny + dy / 2 },
        c2: { x: curve * nx + dx / 2, y: curve * ny + dy / 2 },
        end: { x: dx, y: dy }
      };
    }

    moves.forEach(move => {
      const dx = move[0];
      const dy = move[1];
      const controls = twiddle(dx, dy);

      segments.push({
        c1: { x: x + controls.c1.x, y: y + controls.c1.y },
        c2: { x: x + controls.c2.x, y: y + controls.c2.y },
        end: { x: x + controls.end.x, y: y + controls.end.y }
      });

      x += dx;
      y += dy;
      rawVertices.push({ x, y });
    });

    const verticesForCenter = rawVertices.slice(0, -1);
    const center = verticesForCenter.reduce((sum, vertex) => ({
      x: sum.x + vertex.x,
      y: sum.y + vertex.y
    }), { x: 0, y: 0 });

    center.x /= verticesForCenter.length;
    center.y /= verticesForCenter.length;

    const vertices = verticesForCenter.map(vertex => ({
      x: vertex.x - center.x,
      y: vertex.y - center.y
    }));

    const commands = [`M ${vertices[0].x.toFixed(3)} ${vertices[0].y.toFixed(3)}`];

    segments.forEach(segment => {
      commands.push(
        `C ${(segment.c1.x - center.x).toFixed(3)} ${(segment.c1.y - center.y).toFixed(3)}, ${(segment.c2.x - center.x).toFixed(3)} ${(segment.c2.y - center.y).toFixed(3)}, ${(segment.end.x - center.x).toFixed(3)} ${(segment.end.y - center.y).toFixed(3)}`
      );
    });

    commands.push("Z");

    const tile = {
      label: "",
      bubbleLabel: label,
      color,
      sides: vertices.length,
      sideLength: SIDE_LENGTH,
      radius: radiusFromVertices(vertices),
      startAngleDegrees: 0,
      vertices,
      points: pointsFromVertices(vertices),
      path: commands.join(" "),
      snapRotationTolerance: 181,
      snapDistanceMultiplier: 2.4,
      isAperiodicMonotile: true
    };

    return assignUnitSnapEdges(tile, tile.vertices, new Array(tile.vertices.length).fill(1));
  }

  function equilateralEinsteinRawVertices() {
    // Exact compact outline from John's reference. All vertices lie on the
    // 30-degree triangular/hexagonal grid. Every boundary segment is one unit
    // except the long lower-left edge, which is two units.
    const unit = SIDE_LENGTH;
    const halfRootThree = Math.sqrt(3) / 2;
    return [
      [0, 0],
      [1, 0],
      [1, 1],
      [1 + halfRootThree, 1.5],
      [0.5 + halfRootThree, 1.5 + halfRootThree],
      [1 + halfRootThree, 1.5 + Math.sqrt(3)],
      [1, 2 + Math.sqrt(3)],
      [1 - Math.sqrt(3), 1 + Math.sqrt(3)],
      [1 - Math.sqrt(3), Math.sqrt(3)],
      [-Math.sqrt(3), Math.sqrt(3)],
      [-0.5 - Math.sqrt(3), halfRootThree],
      [-0.5 - halfRootThree, halfRootThree - 0.5],
      [-0.5, halfRootThree]
    ].map(([x, y]) => ({ x: x * unit, y: y * unit }));
  }

  function equilateralEinsteinSegmentCounts() {
    const counts = new Array(13).fill(1);
    counts[6] = 2;
    return counts;
  }

  function makeEquilateralEinsteinTile() {
    const rawVertices = equilateralEinsteinRawVertices();
    const tile = makeCustomPolygonTile("Tile(1,1)", "#90be6d", rawVertices);
    tile.snapDistanceMultiplier = 2.4;
    tile.isAperiodicMonotile = true;
    return assignUnitSnapEdges(tile, tile.vertices, equilateralEinsteinSegmentCounts());
  }

  function makeStegosaurusSpectreTile() {
    const baseVertices = equilateralEinsteinRawVertices();
    const segmentCounts = equilateralEinsteinSegmentCounts();
    const zigzagVertices = [];
    let unitSegmentIndex = 0;

    baseVertices.forEach((start, edgeIndex) => {
      const end = baseVertices[(edgeIndex + 1) % baseVertices.length];
      const unitSegments = segmentCounts[edgeIndex];

      for (let segment = 0; segment < unitSegments; segment += 1) {
        const segmentStart = lerpPoint(start, end, segment / unitSegments);
        const segmentEnd = lerpPoint(start, end, (segment + 1) / unitSegments);
        const dx = segmentEnd.x - segmentStart.x;
        const dy = segmentEnd.y - segmentStart.y;
        const length = Math.hypot(dx, dy) || 1;
        const normal = { x: dy / length, y: -dx / length };
        const direction = unitSegmentIndex % 2 === 0 ? -1 : 1;

        zigzagVertices.push(segmentStart);
        zigzagVertices.push({
          x: segmentStart.x + dx / 2 + normal.x * length / 2 * direction,
          y: segmentStart.y + dy / 2 + normal.y * length / 2 * direction
        });
        unitSegmentIndex += 1;
      }
    });

    const rawCenter = zigzagVertices.reduce((sum, vertex) => ({
      x: sum.x + vertex.x,
      y: sum.y + vertex.y
    }), { x: 0, y: 0 });
    rawCenter.x /= zigzagVertices.length;
    rawCenter.y /= zigzagVertices.length;

    const snapVertices = baseVertices.map(vertex => ({
      x: vertex.x - rawCenter.x,
      y: vertex.y - rawCenter.y
    }));
    const tile = makeCustomPolygonTile("Stegosaurus Spectre", "#f4a261", zigzagVertices);
    tile.snapDistanceMultiplier = 2.4;
    tile.isAperiodicMonotile = true;
    return assignUnitSnapEdges(tile, snapVertices, segmentCounts);
  }

  function makeFrameTile(label, width, height, sockets) {
    const outer = roundedRectanglePath(width, height, 18);
    const holePaths = sockets.map(socket => transformedBubblePath(socket.tileType, socket.x, socket.y, socket.rotation || 0));
    const snapEdgesLocal = sockets.flatMap(socket => transformedSocketEdges(socket.tileType, socket.x, socket.y, socket.rotation || 0));

    return {
      label: "",
      bubbleLabel: label,
      color: "#c7aa72",
      sides: 4,
      sideLength: SIDE_LENGTH,
      radius: Math.hypot(width / 2, height / 2),
      startAngleDegrees: 0,
      vertices: [
        { x: -width / 2, y: -height / 2 },
        { x: width / 2, y: -height / 2 },
        { x: width / 2, y: height / 2 },
        { x: -width / 2, y: height / 2 }
      ],
      path: [outer, ...holePaths].join(" "),
      fillRule: "evenodd",
      snapEdgesLocal,
      isFrame: true
    };
  }

  function makeExactFrameTile(label, color, width, height, path, snapEdgesLocal) {
    return {
      label: "",
      bubbleLabel: label,
      color,
      sides: 4,
      sideLength: SIDE_LENGTH,
      radius: Math.hypot(width / 2, height / 2),
      startAngleDegrees: 0,
      vertices: [
        { x: -width / 2, y: -height / 2 },
        { x: width / 2, y: -height / 2 },
        { x: width / 2, y: height / 2 },
        { x: -width / 2, y: height / 2 }
      ],
      path,
      fillRule: "evenodd",
      snapEdgesLocal,
      isFrame: true,
      isExactSvgFrame: true
    };
  }

  function hexSocketGrid(radius, tileTypes) {
    const offsets = [
      { q: 0, r: 0 }
    ];

    for (let ring = 1; ring <= radius; ring += 1) {
      let q = -ring;
      let r = 0;
      const directions = [
        { q: 1, r: -1 },
        { q: 1, r: 0 },
        { q: 0, r: 1 },
        { q: -1, r: 1 },
        { q: -1, r: 0 },
        { q: 0, r: -1 }
      ];

      directions.forEach(direction => {
        for (let step = 0; step < ring; step += 1) {
          offsets.push({ q, r });
          q += direction.q;
          r += direction.r;
        }
      });
    }

    return offsets.slice(0, tileTypes.length).map((offset, index) => ({
      tileType: tileTypes[index],
      x: 138 * offset.q + 69 * offset.r,
      y: 120 * offset.r,
      rotation: 0
    }));
  }

  // Equal-area display normalization against Tile(1,1). This keeps the Hat
  // and Turtle visually comparable without changing either tile's proportions.
  const HAT_DISPLAY_SCALE = 0.7690945006604258;
  const TURTLE_DISPLAY_SCALE = 0.6878990338391876;

  function penroseMatchingArcPath(center, startAlong, endAlong, radius, largeArc, sweep) {
    function pointAtRadius(target) {
      const length = distance(center, target);
      return {
        x: center.x + ((target.x - center.x) * radius) / length,
        y: center.y + ((target.y - center.y) * radius) / length
      };
    }

    const start = pointAtRadius(startAlong);
    const end = pointAtRadius(endAlong);
    return `M ${start.x.toFixed(3)} ${start.y.toFixed(3)} A ${radius.toFixed(3)} ${radius.toFixed(3)} 0 ${largeArc ? 1 : 0} ${sweep ? 1 : 0} ${end.x.toFixed(3)} ${end.y.toFixed(3)}`;
  }

  function makePenroseKiteDartTile(kind) {
    const phi = (1 + Math.sqrt(5)) / 2;
    const longSide = SIDE_LENGTH;
    const shortSide = longSide / phi;
    const cos18 = Math.cos(Math.PI / 10);
    const sin18 = Math.sin(Math.PI / 10);
    const isKite = kind === "kite";
    const rawVertices = isKite
      ? [
          { x: 0, y: 0 },
          { x: shortSide * cos18, y: shortSide * sin18 },
          { x: 0, y: longSide },
          { x: -shortSide * cos18, y: shortSide * sin18 }
        ]
      : [
          { x: -shortSide * cos18, y: -shortSide * sin18 },
          { x: 0, y: 0 },
          { x: shortSide * cos18, y: -shortSide * sin18 },
          { x: 0, y: shortSide }
        ];
    const center = rawVertices.reduce((sum, point) => ({ x: sum.x + point.x / 4, y: sum.y + point.y / 4 }), { x: 0, y: 0 });
    const vertices = rawVertices.map(point => ({ x: point.x - center.x, y: point.y - center.y }));
    const greenCenterIndex = isKite ? 0 : 1;
    const greenNeighborIndices = isKite ? [3, 1] : [0, 2];
    const redCenterIndex = isKite ? 2 : 3;
    const redNeighborIndices = isKite ? [3, 1] : [0, 2];
    const greenRadius = shortSide / 2;
    const redRadius = isKite ? longSide - greenRadius : shortSide - greenRadius;
    const edgeIndices = [[0, 1], [1, 2], [2, 3], [3, 0]];
    const shortEdgeIndexSet = new Set(isKite ? [0, 3] : [0, 1]);
    return {
      label: "",
      bubbleLabel: isKite ? "Penrose Kite" : "Penrose Dart",
      color: isKite ? "#b8b8b8" : "#c7c7c7",
      sides: 4,
      sideLength: longSide,
      radius: radiusFromVertices(vertices),
      vertices,
      points: pointsFromVertices(vertices),
      defaultRotation: 0,
      snapRotationTolerance: 181,
      snapEdgesLocal: edgeIndices.map(([startIndex, endIndex], index) => ({
          start: { ...vertices[startIndex] },
          end: { ...vertices[endIndex] },
          index,
          bite: null,
          isBubbleEdge: false,
          isUnitSnapEdge: !shortEdgeIndexSet.has(index),
          penroseLengthClass: shortEdgeIndexSet.has(index) ? "inverse-phi" : "unit"
      })),
      decorations: [
        {
          className: "penrose-decoration penrose-matching-arc penrose-green-arc",
          d: penroseMatchingArcPath(
            vertices[greenCenterIndex],
            vertices[greenNeighborIndices[0]],
            vertices[greenNeighborIndices[1]],
            greenRadius,
            !isKite,
            false
          ),
          stroke: "#169b45",
          strokeWidth: 5
        },
        {
          className: "penrose-decoration penrose-matching-arc penrose-red-arc",
          d: penroseMatchingArcPath(
            vertices[redCenterIndex],
            vertices[redNeighborIndices[0]],
            vertices[redNeighborIndices[1]],
            redRadius,
            false,
            true
          ),
          stroke: "#e3262e",
          strokeWidth: 5
        }
      ],
      isPenroseKiteDart: true
    };
  }

