  /*
    Build an exact frame opening from a patch of mutually snapped bubble tiles.
    Shared chords cancel in pairs; only the exterior arcs and their snap edges
    remain. This keeps the frame geometry tied to the actual app tiles instead
    of to a separately traced approximation.
  */
  function makeExactFrameFromBubblePatch(label, color, width, height, patch) {
    const exteriorByChord = new Map();

    function transformPatchPoint(point, placement) {
      const radians = (placement.rotation || 0) * Math.PI / 180;
      const cosine = Math.cos(radians);
      const sine = Math.sin(radians);
      return {
        x: placement.x + point.x * cosine - point.y * sine,
        y: placement.y + point.x * sine + point.y * cosine
      };
    }

    function chordKey(start, end) {
      const startKey = `${Math.round(start.x * 100)},${Math.round(start.y * 100)}`;
      const endKey = `${Math.round(end.x * 100)},${Math.round(end.y * 100)}`;
      return startKey < endKey ? `${startKey}|${endKey}` : `${endKey}|${startKey}`;
    }

    patch.forEach(placement => {
      const definition = tileDefinitions[placement.type];
      if (!definition || !Array.isArray(definition.vertices) || !Array.isArray(definition.bites)) return;

      definition.vertices.forEach((vertex, index) => {
        const start = transformPatchPoint(vertex, placement);
        const end = transformPatchPoint(definition.vertices[(index + 1) % definition.vertices.length], placement);
        const key = chordKey(start, end);

        if (exteriorByChord.has(key)) {
          exteriorByChord.delete(key);
        } else {
          exteriorByChord.set(key, {
            start,
            end,
            bite: definition.bites[index] === 1 ? 1 : 0
          });
        }
      });
    });

    const unorderedEdges = Array.from(exteriorByChord.values());
    const orderedEdges = [];
    if (unorderedEdges.length) orderedEdges.push(unorderedEdges.shift());

    while (unorderedEdges.length) {
      const currentEnd = orderedEdges[orderedEdges.length - 1].end;
      const nextIndex = unorderedEdges.findIndex(edge => (
        Math.hypot(edge.start.x - currentEnd.x, edge.start.y - currentEnd.y) < 0.05
      ));
      if (nextIndex < 0) break;
      orderedEdges.push(unorderedEdges.splice(nextIndex, 1)[0]);
    }

    const boundaryPoints = orderedEdges.flatMap(edge => [edge.start, edge.end]);
    const minX = Math.min(...boundaryPoints.map(point => point.x));
    const maxX = Math.max(...boundaryPoints.map(point => point.x));
    const minY = Math.min(...boundaryPoints.map(point => point.y));
    const maxY = Math.max(...boundaryPoints.map(point => point.y));
    const centerX = (minX + maxX) / 2;
    const centerY = (minY + maxY) / 2;
    const centeredEdges = orderedEdges.map((edge, index) => ({
      start: { x: edge.start.x - centerX, y: edge.start.y - centerY },
      end: { x: edge.end.x - centerX, y: edge.end.y - centerY },
      index,
      bite: edge.bite,
      isBubbleEdge: true,
      isFrameSocket: true
    }));

    const holePath = centeredEdges.length
      ? [
          `M ${centeredEdges[0].start.x.toFixed(3)} ${centeredEdges[0].start.y.toFixed(3)}`,
          ...centeredEdges.map(edge => (
            `A ${SIDE_LENGTH.toFixed(3)} ${SIDE_LENGTH.toFixed(3)} 0 0 ${edge.bite === 1 ? 0 : 1} ${edge.end.x.toFixed(3)} ${edge.end.y.toFixed(3)}`
          )),
          "Z"
        ].join(" ")
      : "";

    return makeExactFrameTile(
      label,
      color,
      width,
      height,
      `${roundedRectanglePath(width, height, 18)} ${holePath}`,
      centeredEdges
    );
  }

