  function arcPath(cx, cy, r, startDegrees, endDegrees) {
    const startRadians = startDegrees * Math.PI / 180;
    const endRadians = endDegrees * Math.PI / 180;
    const start = {
      x: cx + r * Math.cos(startRadians),
      y: cy + r * Math.sin(startRadians)
    };
    const end = {
      x: cx + r * Math.cos(endRadians),
      y: cy + r * Math.sin(endRadians)
    };
    const largeArc = Math.abs(endDegrees - startDegrees) > 180 ? 1 : 0;
    const sweep = endDegrees > startDegrees ? 1 : 0;

    return `M ${start.x.toFixed(3)} ${start.y.toFixed(3)} A ${r} ${r} 0 ${largeArc} ${sweep} ${end.x.toFixed(3)} ${end.y.toFixed(3)}`;
  }

  function formatPoint(point) {
    return `${point.x.toFixed(3)} ${point.y.toFixed(3)}`;
  }

  function cornerCurvePath(vertices, cornerIndex, amount = 0.42) {
    const corner = vertices[cornerIndex];
    const previous = vertices[(cornerIndex - 1 + vertices.length) % vertices.length];
    const next = vertices[(cornerIndex + 1) % vertices.length];
    const start = lerpPoint(corner, previous, amount);
    const end = lerpPoint(corner, next, amount);
    return `M ${formatPoint(start)} Q ${formatPoint(corner)} ${formatPoint(end)}`;
  }

  function sideBridgeCurvePath(vertices, edgeA, edgeB, controlIndex, tA = 0.52, tB = 0.48, controlPull = 0.16) {
    const a0 = vertices[edgeA % vertices.length];
    const a1 = vertices[(edgeA + 1) % vertices.length];
    const b0 = vertices[edgeB % vertices.length];
    const b1 = vertices[(edgeB + 1) % vertices.length];
    const start = lerpPoint(a0, a1, tA);
    const end = lerpPoint(b0, b1, tB);
    const controlVertex = vertices[controlIndex % vertices.length];
    const control = {
      x: controlVertex.x * (1 - controlPull) + ((start.x + end.x) / 2) * controlPull,
      y: controlVertex.y * (1 - controlPull) + ((start.y + end.y) / 2) * controlPull
    };
    return `M ${formatPoint(start)} Q ${formatPoint(control)} ${formatPoint(end)}`;
  }

  function addPenroseMarkings() {
    // Penrose rhombs are intentionally unmarked in this build.
    if (tileDefinitions.PRTHICK) tileDefinitions.PRTHICK.decorations = [];
    if (tileDefinitions.PRTHIN) tileDefinitions.PRTHIN.decorations = [];
  }


  addPenroseMarkings();

  let nextCanvasImageNumber = 1;

  function registerCanvasImageDefinition(tileType, imageData, width, height) {
    const safeWidth = Number(width);
    const safeHeight = Number(height);
    if (!tileType || typeof imageData !== "string" || !/^data:image\/(png|jpe?g|webp|gif)[;,]/i.test(imageData) ||
        !Number.isFinite(safeWidth) || !Number.isFinite(safeHeight) || safeWidth <= 0 || safeHeight <= 0) return null;

    const halfWidth = safeWidth / 2;
    const halfHeight = safeHeight / 2;
    const vertices = [
      { x: -halfWidth, y: -halfHeight },
      { x: halfWidth, y: -halfHeight },
      { x: halfWidth, y: halfHeight },
      { x: -halfWidth, y: halfHeight }
    ];

    tileDefinitions[tileType] = {
      label: "",
      bubbleLabel: "Pasted image",
      vertices,
      points: pointsFromVertices(vertices),
      radius: Math.hypot(halfWidth, halfHeight),
      isCanvasImage: true,
      imageData,
      imageWidth: safeWidth,
      imageHeight: safeHeight
    };
    return tileType;
  }

  function ensureCanvasImageDefinition(tile) {
    if (!tile || !String(tile.tileType || "").startsWith("CANVAS_IMAGE_")) return null;
    if (tileDefinitions[tile.tileType]) return tile.tileType;
    return registerCanvasImageDefinition(tile.tileType, tile.imageData, tile.imageWidth, tile.imageHeight);
  }

  function canvasImageFields(tileType) {
    const definition = tileDefinitions[tileType];
    if (!definition || !definition.isCanvasImage) return {};
    return {
      imageData: definition.imageData,
      imageWidth: definition.imageWidth,
      imageHeight: definition.imageHeight
    };
  }


  function tileDisplayName(tileType) {
    const names = {
      H2A: "H2A",
      H5: "H5",
      B0: "bubble tile 0",
      B1: "bubble tile 1",
      B2A: "bubble tile 2A",
      B2B: "bubble tile 2B",
      B2C: "bubble tile 2C",
      B3A: "bubble tile 3A",
      B3ASTAR: "bubble tile 3A*",
      B3B: "bubble tile 3B",
      B3C: "bubble tile 3C",
      B4A: "bubble tile 4A",
      B4B: "bubble tile 4B",
      B4C: "bubble tile 4C",
      B5: "bubble tile 5",
      B6: "bubble tile 6",
      T0: "triangular bubble tile 0",
      T1: "triangular bubble tile 1",
      T2: "triangular bubble tile 2",
      T3: "triangular bubble tile 3",
      Q0: "square bubble tile 0",
      Q1: "square bubble tile 1",
      Q2A: "square bubble tile 2A",
      Q2B: "square bubble tile 2B",
      Q3: "square bubble tile 3",
      Q4: "square bubble tile 4",
      PH0: "hexagonal puzzle tile 0",
      PH1: "hexagonal puzzle tile 1",
      PH2A: "hexagonal puzzle tile 2A",
      PH2B: "hexagonal puzzle tile 2B",
      PH2C: "hexagonal puzzle tile 2C",
      PH3A: "hexagonal puzzle tile 3A",
      PH3ASTAR: "hexagonal puzzle tile 3A*",
      PH3B: "hexagonal puzzle tile 3B",
      PH3C: "hexagonal puzzle tile 3C",
      PH4A: "hexagonal puzzle tile 4A",
      PH4B: "hexagonal puzzle tile 4B",
      PH4C: "hexagonal puzzle tile 4C",
      PH5: "hexagonal puzzle tile 5",
      PH6: "hexagonal puzzle tile 6",
      PT0: "triangular puzzle tile 0",
      PT1: "triangular puzzle tile 1",
      PT2: "triangular puzzle tile 2",
      PT3: "triangular puzzle tile 3",
      PQ0: "square puzzle tile 0",
      PQ1: "square puzzle tile 1",
      PQ2A: "square puzzle tile 2A",
      PQ2B: "square puzzle tile 2B",
      PQ3: "square puzzle tile 3",
      PQ4: "square puzzle tile 4",
      FMINI: "Small Frame",
      F13: "13 Tile Frame",
      FLARGE: "Large Frame",
      PRTHICK: "Penrose thick rhomb",
      PRTHIN: "Penrose thin rhomb",
      PKITE: "Penrose kite",
      PDART: "Penrose dart",
      OP_STAR5: "5-point star (5/2)",
      OP_STAR6: "6-point star (6/2)",
      OP_STAR8: "8-point star (8/2)",
      OP_RIGHT_ISO_TRI: "45-45-90 triangle",
      OP_TANGRAM_PARA: "Tangram parallelogram",
      OP_RHOMBUS45: "45-degree rhombus",
      HAT: "Hat monotile",
      TURTLE: "Turtle monotile",
      SPECTRE: "Spectre monotile",
      EQUILATERAL_EINSTEIN: "Tile(1,1) monotile",
      STEGOSAURUS_SPECTRE: "Stegosaurus Spectre monotile",
      TET_I: "I tetromino",
      TET_O: "O tetromino",
      TET_T: "T tetromino",
      TET_L: "L tetromino",
      TET_S: "S tetromino",
      PENT_F: "F pentomino",
      PENT_I: "I pentomino",
      PENT_L: "L pentomino",
      PENT_N: "N pentomino",
      PENT_P: "P pentomino",
      PENT_T: "T pentomino",
      PENT_U: "U pentomino",
      PENT_V: "V pentomino",
      PENT_W: "W pentomino",
      PENT_X: "X pentomino",
      PENT_Y: "Y pentomino",
      PENT_Z: "Z pentomino",
      SH_TRAP: "trapezoid",
      SH_PARA: "parallelogram",
      SH_RHOMBUS: "rhombus",
      SH_RECT: "rectangle",
      SH_RIGHT_TRI: "right triangle",
      SH_SMALL_TRI: "small triangle",
      SH_CHEVRON: "chevron",
      SH_KITE: "kite",
      SH_DART: "dart",
      OP_RECT: "2×1 rectangle",
      OP_TRAP: "1-1-1-2 trapezoid",
      PRTHICK: "Penrose thick rhomb",
      PRTHIN: "Penrose thin rhomb",
      OP_RHOMBUS: "60° rhombus",
      OP_PACMAN: "Pac-Man hexagon",
      OP_PACMAN_PENT: "Pac-Man pentagon",
      OP_PACMAN_OCT2: "Pac-Man octagon 1",
      OP_PACMAN_OCT3: "Pac-Man octagon 2",
      OP_SQUIGGLE_OCT: "Squiggle octagon",
      TRI: "triangle",
      SQUARE: "square",
      PENT: "pentagon",
      HEX: "hexagon",
      HEPT: "heptagon",
      OCT: "octagon",
      NGON: "n-gon"
    };

    if (names[tileType]) return names[tileType];

    if (tileType === "BVLENS") return "bubble variant arc lens";
    if (/^BVH/.test(tileType)) return "bubble variant hex chevron tile " + (tileDefinitions[tileType] && tileDefinitions[tileType].bubbleLabel ? tileDefinitions[tileType].bubbleLabel : tileType);
    if (/^BVO/.test(tileType)) return "bubble variant octagon chevron tile " + (tileDefinitions[tileType] && tileDefinitions[tileType].bubbleLabel ? tileDefinitions[tileType].bubbleLabel : tileType);
    if (/^RB/.test(tileType)) return "four-sided bubble tile " + (tileDefinitions[tileType] && tileDefinitions[tileType].bubbleLabel ? tileDefinitions[tileType].bubbleLabel : tileType);
    if (/^FV/.test(tileType)) return "pentagonal bubble tile " + (tileDefinitions[tileType] && tileDefinitions[tileType].bubbleLabel ? tileDefinitions[tileType].bubbleLabel : tileType);
    if (/^SF/.test(tileType)) return "soft bubble tile " + (tileDefinitions[tileType] && tileDefinitions[tileType].bubbleLabel ? tileDefinitions[tileType].bubbleLabel : tileType);

    const convertedBubbleMatch = String(tileType).match(/^BUBBLE_(.+)$/);
    if (convertedBubbleMatch) {
      const sourceName = tileDisplayName(convertedBubbleMatch[1]);
      return "bubble " + sourceName;
    }

    const arcVariant = parseArcVariantTileType(tileType);
    if (arcVariant && arcVariant.sourceType === "BUBBLE_OP_TRAP") {
      return "five-sided trapezoid bubble tile " + arcVariant.bitString;
    }
    if (arcVariant && /^FV/.test(arcVariant.sourceType)) {
      return "pentagonal bubble tile " + (tileDefinitions[tileType] && tileDefinitions[tileType].bubbleLabel ? tileDefinitions[tileType].bubbleLabel : arcVariant.bitString);
    }
    if (arcVariant) return "custom-arc " + tileDisplayName(arcVariant.sourceType);

    const polygonVariantMatch = String(tileType).match(/^POLYV_(.+)$/);
    if (polygonVariantMatch) return "polygon " + tileDisplayName(polygonVariantMatch[1]);

    const ngonMatch = String(tileType).match(/^NGON(\d+)$/);
    if (ngonMatch) return ngonMatch[1] + "-gon";

    return tileType;
  }



  function parseArcVariantTileType(tileType) {
    const typeName = String(tileType || "");
    if (!typeName.startsWith("ARCV_")) return null;

    const lastUnderscore = typeName.lastIndexOf("_");
    if (lastUnderscore <= 5) return null;

    const sourceType = typeName.slice(5, lastUnderscore);
    const bitString = typeName.slice(lastUnderscore + 1);
    if (!/^[01]+$/.test(bitString)) return null;

    return {
      sourceType,
      bites: bitString.split("").map(value => value === "1" ? 1 : 0),
      bitString
    };
  }

  function arcVariantBaseType(tileType) {
    const parsed = parseArcVariantTileType(tileType);
    if (parsed) return parsed.sourceType;

    const definition = tileDefinitions[tileType];
    return definition && definition.arcSourceType ? definition.arcSourceType : tileType;
  }


  function isEinsteinFamilyTileType(tileType) {
    const typeName = String(tileType || "");
    const baseType = typeName.startsWith("BUBBLE_") ? typeName.slice(7) : arcVariantBaseType(typeName);
    const definition = tileDefinitions[baseType] || tileDefinitions[typeName];
    const convertedFrom = definition ? (definition.convertedFrom || definition.convertedFromType || definition.arcSourceType) : null;
    const source = convertedFrom || baseType;
    return source === "HAT" || source === "TURTLE" || source === "SPECTRE" || source === "EQUILATERAL_EINSTEIN" || source === "STEGOSAURUS_SPECTRE";
  }

  function isBubbleConversionExcludedTileType(tileType) {
    const resolved = ensureDynamicTileDefinition(tileType) || tileType;
    const definition = tileDefinitions[resolved];
    return resolved === "BVLENS" || !!(definition && (definition.isFrame || definition.isCanvasImage || definition.isPenroseKiteDart)) || isEinsteinFamilyTileType(resolved);
  }

  function isSingleArcEditableDefinition(definition) {
    return !!(
      definition &&
      Array.isArray(definition.vertices) &&
      Array.isArray(definition.bites) &&
      definition.vertices.length >= 3 &&
      definition.vertices.length === definition.bites.length &&
      !definition.isArcLensTile &&
      !definition.isSoftTile &&
      !definition.isFrame &&
      !definition.isConvertedMonotileBubble &&
      !isEinsteinFamilyTileType(definition.convertedFrom || definition.convertedFromType || definition.arcSourceType || definition.baseType || "")
    );
  }

  function arcVariantTypeName(sourceType, bites) {
    return "ARCV_" + sourceType + "_" + bites.map(value => value === 1 ? "1" : "0").join("");
  }

  function ensureArcVariantTileDefinition(sourceType, bites) {
    let resolvedSourceType = ensureDynamicTileDefinition(sourceType) || sourceType;
    const sourceParsed = parseArcVariantTileType(resolvedSourceType);

    if (sourceParsed) {
      resolvedSourceType = sourceParsed.sourceType;
    }

    const sourceDefinition = tileDefinitions[resolvedSourceType];
    if (!sourceDefinition || !Array.isArray(sourceDefinition.vertices)) return null;

    const normalizedBites = bites.map(value => value === 1 ? 1 : 0);
    if (normalizedBites.length !== sourceDefinition.vertices.length) return null;

    const typeName = arcVariantTypeName(resolvedSourceType, normalizedBites);

    if (!tileDefinitions[typeName]) {
      const vertices = sourceDefinition.vertices.map(vertex => ({ ...vertex }));
      const variantPath = sourceDefinition.isPuzzleTile
        ? puzzleTilePath(vertices, normalizedBites)
        : (sourceDefinition.isConvertedBubbleTile ? bubbleProfilePathFromVertices(vertices, normalizedBites) : bubbleTilePath(vertices, normalizedBites));
      tileDefinitions[typeName] = {
        ...sourceDefinition,
        label: "",
        bubbleLabel: sourceDefinition.bubbleLabel || sourceDefinition.label || tileDisplayName(resolvedSourceType),
        vertices,
        bites: normalizedBites,
        path: variantPath,
        points: undefined,
        isArcVariant: true,
        arcSourceType: resolvedSourceType,
        isConvertedBubbleTile: !!sourceDefinition.isConvertedBubbleTile,
        convertedFrom: sourceDefinition.convertedFrom || sourceDefinition.convertedFromType || null,
        isConvertedMonotileBubble: !!sourceDefinition.isConvertedMonotileBubble,
        snapRotationTolerance: Number.isFinite(sourceDefinition.snapRotationTolerance) ? sourceDefinition.snapRotationTolerance : 181,
        snapDistanceMultiplier: Number.isFinite(sourceDefinition.snapDistanceMultiplier) ? sourceDefinition.snapDistanceMultiplier : 1
      };
    }

    return typeName;
  }

  function ensureDynamicTileDefinition(tileType) {
    const typeName = String(tileType);
    const arcVariant = parseArcVariantTileType(typeName);
    if (arcVariant) {
      const sourceType = ensureDynamicTileDefinition(arcVariant.sourceType) || arcVariant.sourceType;
      return ensureArcVariantTileDefinition(sourceType, arcVariant.bites);
    }

    const bubbleMatch = typeName.match(/^BUBBLE_(.+)$/);
    if (bubbleMatch) {
      const sourceType = ensureDynamicTileDefinition(bubbleMatch[1]) || bubbleMatch[1];
      return ensureConvertedBubbleTileDefinition(sourceType);
    }

    const polygonVariantMatch = typeName.match(/^POLYV_(.+)$/);
    if (polygonVariantMatch) {
      return ensurePolygonVariantTileDefinition(polygonVariantMatch[1]);
    }

    const ngonMatch = typeName.match(/^NGON(\d+)$/);
    if (!ngonMatch) return null;

    const sides = Math.max(3, Math.min(120, Number(ngonMatch[1])));
    const normalizedType = "NGON" + sides;

    if (!tileDefinitions[normalizedType]) {
      tileDefinitions[normalizedType] = makeRegularTile("", "#a3d5ff", sides, -90);
      tileDefinitions[normalizedType].bubbleLabel = sides + "-gon";
      tileDefinitions[normalizedType].isDynamicNgon = true;
    }

    return normalizedType;
  }

  function openNgonDialog() {
    if (!ngonModal || !ngonSidesInput) return;
    ngonSidesInput.value = "10";
    ngonSidesInput.setCustomValidity("");
    ngonModal.hidden = false;
    window.setTimeout(() => {
      ngonSidesInput.focus();
      ngonSidesInput.select();
    }, 0);
  }

  function closeNgonDialog() {
    if (!ngonModal) return;
    ngonModal.hidden = true;
  }

  function addNgonFromDialog() {
    if (!ngonSidesInput) return;
    const text = String(ngonSidesInput.value).trim();
    const sides = Number(text);
    if (!/^\d+$/.test(text) || !Number.isInteger(sides) || sides < 3 || sides > 120) {
      ngonSidesInput.setCustomValidity("Enter a whole number from 3 to 120.");
      ngonSidesInput.reportValidity();
      ngonSidesInput.focus();
      setStatus("Enter a whole number from 3 to 120 for the n-gon.");
      return;
    }
    ngonSidesInput.setCustomValidity("");

    const tileType = ensureDynamicTileDefinition("NGON" + sides);
    if (!tileType) return;

    const x = 250 + nextNewTileOffset;
    const y = 180 + nextNewTileOffset;
    const newId = addPlacedTile(tileType, x, y, defaultRotationForTileType(tileType));
    if (!newId) return;
    recordRecentTraySet("regular");

    nextNewTileOffset += 35;
    if (nextNewTileOffset > 210) nextNewTileOffset = 0;

    hideSnapPreview();
    recordHistory();
    closeNgonDialog();
    setStatus("Added regular " + sides + "-gon.");
  }

  function splitVerticesIntoUnitEdges(vertices) {
    if (!Array.isArray(vertices) || vertices.length < 2) return null;

    const split = [];
    vertices.forEach((start, edgeIndex) => {
      const end = vertices[(edgeIndex + 1) % vertices.length];
      const count = edgeSegmentCount(start, end);

      for (let segmentIndex = 0; segmentIndex < count; segmentIndex += 1) {
        split.push(lerpPoint(start, end, segmentIndex / count));
      }
    });

    return split;
  }

  function segmentCountsFromVertices(vertices) {
    if (!Array.isArray(vertices) || vertices.length < 2) return [];
    return vertices.map((start, edgeIndex) => edgeSegmentCount(start, vertices[(edgeIndex + 1) % vertices.length]));
  }

  function splitVerticesForBubbleConversion(tileType) {
    const s = SIDE_LENGTH;

    if (tileType === "OP_RECT") {
      return centeredVertices([
        { x: -s, y: -s / 2 },
        { x: 0, y: -s / 2 },
        { x: s, y: -s / 2 },
        { x: s, y: s / 2 },
        { x: 0, y: s / 2 },
        { x: -s, y: s / 2 }
      ]);
    }

    if (tileType === "OP_TRAP") {
      const height = Math.sqrt(3) * s / 2;
      return centeredVertices([
        { x: -s, y: height / 2 },
        { x: 0, y: height / 2 },
        { x: s, y: height / 2 },
        { x: s / 2, y: -height / 2 },
        { x: -s / 2, y: -height / 2 }
      ]);
    }

    const definition = tileDefinitions[tileType];
    if (!definition || !Array.isArray(definition.vertices)) return null;

    /*
      Keep this generic and persistent: any polygon converted to a bubble tile
      should expose one editable/snap edge per unit side length.  This is what
      makes 2-length Einstein/Hat/Turtle edges show midpoint dots in Reverse
      One Arc and lets the two unit arcs snap/edit independently.
    */
    return splitVerticesIntoUnitEdges(definition.vertices);
  }

  function signedAreaFromVertices(vertices) {
    if (!Array.isArray(vertices) || vertices.length < 3) return 0;

    let area = 0;

    for (let i = 0; i < vertices.length; i += 1) {
      const current = vertices[i];
      const next = vertices[(i + 1) % vertices.length];
      area += current.x * next.y - next.x * current.y;
    }

    return area / 2;
  }

  function bubbleProfilePathFromVertices(vertices, bites) {
    if (!Array.isArray(vertices) || vertices.length < 2) return "";

    const signedArea = signedAreaFromVertices(vertices);
    const outsideSweep = signedArea >= 0 ? 1 : 0;
    const commands = [`M ${vertices[0].x.toFixed(3)} ${vertices[0].y.toFixed(3)}`];

    for (let edgeIndex = 0; edgeIndex < vertices.length; edgeIndex += 1) {
      const start = vertices[edgeIndex];
      const end = vertices[(edgeIndex + 1) % vertices.length];
      const segmentCount = edgeSegmentCount(start, end);
      const isBite = bites && bites[edgeIndex] === 1;
      const sweep = isBite ? 1 - outsideSweep : outsideSweep;

      for (let segmentIndex = 0; segmentIndex < segmentCount; segmentIndex += 1) {
        const segmentStart = lerpPoint(start, end, segmentIndex / segmentCount);
        const segmentEnd = lerpPoint(start, end, (segmentIndex + 1) / segmentCount);
        const radius = Math.hypot(segmentEnd.x - segmentStart.x, segmentEnd.y - segmentStart.y) || SIDE_LENGTH;
        commands.push(`A ${radius.toFixed(3)} ${radius.toFixed(3)} 0 0 ${sweep} ${segmentEnd.x.toFixed(3)} ${segmentEnd.y.toFixed(3)}`);
      }
    }

    commands.push("Z");
    return commands.join(" ");
  }

  function makeBubblePolygonDefinitionFromTileType(tileType) {
    const resolvedTileType = ensureDynamicTileDefinition(tileType) || tileType;
    const sourceDefinition = tileDefinitions[resolvedTileType];
    if (!sourceDefinition || !Array.isArray(sourceDefinition.vertices)) return null;

    const vertices = splitVerticesForBubbleConversion(resolvedTileType);
    if (!vertices || vertices.length < 3) return null;

    // To Bubble Tile should consistently create all-out arcs.
    // bubbleProfilePathFromVertices computes the outward sweep from the polygon winding,
    // so the initial bite array should be all 0, regardless of clockwise/counterclockwise order.
    const bites = new Array(vertices.length).fill(0);
    const sourceName = sourceDefinition.bubbleLabel || sourceDefinition.label || tileDisplayName(resolvedTileType);

    return {
      label: "",
      bubbleLabel: "Bubble " + sourceName,
      color: sourceDefinition.color || "#ffd21f",
      sides: vertices.length,
      sideLength: SIDE_LENGTH,
      radius: radiusFromVertices(vertices),
      startAngleDegrees: sourceDefinition.startAngleDegrees || 0,
      vertices,
      bites,
      path: bubbleProfilePathFromVertices(vertices, bites),
      isConvertedBubbleTile: true,
      convertedFrom: resolvedTileType,
      defaultRotation: sourceDefinition.defaultRotation || 0,
      snapRotationTolerance: Number.isFinite(sourceDefinition.snapRotationTolerance) ? Math.max(181, sourceDefinition.snapRotationTolerance) : 181,
      snapDistanceMultiplier: Number.isFinite(sourceDefinition.snapDistanceMultiplier) ? Math.max(2.8, sourceDefinition.snapDistanceMultiplier) : 2.8,
      isConvertedMonotileBubble: !!sourceDefinition.isAperiodicMonotile,
      /*
        Important for Einstein/Hat/Turtle bubble conversions:
        keep the visually split bubble vertices for Reverse One Arc, but snap
        against the original monotile edge chords.  The monotile has both unit
        edges and sqrt(3)-length edges; splitting the sqrt(3) edges into two
        equal pieces made some sides impossible to snap correctly.
      */
      snapEdgesLocal: sourceDefinition.isAperiodicMonotile && Array.isArray(sourceDefinition.snapEdgesLocal)
        ? sourceDefinition.snapEdgesLocal.map(edge => ({
            ...edge,
            isConvertedBubbleEdge: true,
            isConvertedMonotileBubbleEdge: true,
            snapDistanceMultiplier: Math.max(3.2, edge.snapDistanceMultiplier || sourceDefinition.snapDistanceMultiplier || 1)
          }))
        : undefined
    };
  }

  function convertedBubbleTileType(tileType) {
    const resolvedTileType = ensureDynamicTileDefinition(tileType) || tileType;
    if (isBubbleConversionExcludedTileType(resolvedTileType)) return null;
    if (!tileDefinitions[resolvedTileType]) return null;
    return "BUBBLE_" + resolvedTileType;
  }

  function ensureConvertedBubbleTileDefinition(tileType) {
    const convertedType = convertedBubbleTileType(tileType);
    if (!convertedType) return null;

    if (!tileDefinitions[convertedType]) {
      const definition = makeBubblePolygonDefinitionFromTileType(tileType);
      if (!definition) return null;
      tileDefinitions[convertedType] = definition;
    }

    return convertedType;
  }

  function polygonVariantTypeName(sourceType) {
    return "POLYV_" + String(sourceType || "CUSTOM").replace(/[^A-Za-z0-9]+/g, "_");
  }

  function sourcePolygonTypeForBubbleDefinition(definition, tileType) {
    if (!definition) return null;

    const directSource = definition.convertedFrom || definition.convertedFromType;
    if (directSource && tileDefinitions[directSource] && !Array.isArray(tileDefinitions[directSource].bites)) {
      return directSource;
    }

    const baseType = arcVariantBaseType(tileType);
    const baseDefinition = tileDefinitions[baseType];
    const baseSource = baseDefinition && (baseDefinition.convertedFrom || baseDefinition.convertedFromType);
    if (baseSource && tileDefinitions[baseSource] && !Array.isArray(tileDefinitions[baseSource].bites)) {
      return baseSource;
    }

    if (baseDefinition && !Array.isArray(baseDefinition.bites) && !baseDefinition.isFrame) {
      return baseType;
    }

    return null;
  }

  function ensurePolygonVariantTileDefinition(tileType) {
    const resolvedTileType = ensureDynamicTileDefinition(tileType) || tileType;
    const definition = tileDefinitions[resolvedTileType];
    if (!definition || !Array.isArray(definition.vertices) || definition.isFrame) return null;

    const sourcePolygonType = sourcePolygonTypeForBubbleDefinition(definition, resolvedTileType);
    if (sourcePolygonType) return sourcePolygonType;

    const baseType = arcVariantBaseType(resolvedTileType);
    const baseDefinition = tileDefinitions[baseType] || definition;
    if (!Array.isArray(baseDefinition.vertices)) return null;

    const typeName = polygonVariantTypeName(baseType);
    if (!tileDefinitions[typeName]) {
      const vertices = baseDefinition.vertices.map(vertex => ({ ...vertex }));
      tileDefinitions[typeName] = {
        label: "",
        bubbleLabel: "Polygon " + (baseDefinition.bubbleLabel || baseDefinition.label || tileDisplayName(baseType)),
        color: baseDefinition.color || "#a3d5ff",
        sides: vertices.length,
        sideLength: baseDefinition.sideLength || SIDE_LENGTH,
        radius: radiusFromVertices(vertices),
        startAngleDegrees: baseDefinition.startAngleDegrees || 0,
        defaultRotation: baseDefinition.defaultRotation || 0,
        vertices,
        points: pointsFromVertices(vertices),
        isPolygonVariant: true,
        polygonSourceType: baseType
      };
    }

    return typeName;
  }

  function convertSelectedBubbleTilesToPolygons() {
    const ids = selectedIds().filter(id => tiles[id]);

    if (ids.length === 0) {
      setStatus("Select a bubble or puzzle-edge tile to convert to polygon edges.");
      return;
    }

    let convertedCount = 0;
    let styleOnlyCount = 0;

    ids.forEach(id => {
      const state = tiles[id];
      const definition = tileDefinitions[state.tileType];
      if (!definition || !Array.isArray(definition.vertices) || definition.isFrame || definition.isArcLensTile) return;

      const hasBubbleEdges = Array.isArray(definition.bites) || tileEdgeDecoration(state) !== "none";
      if (!hasBubbleEdges) return;

      const polygonType = ensurePolygonVariantTileDefinition(state.tileType);

      if (polygonType && polygonType !== state.tileType) {
        state.tileType = polygonType;
        state.edgeDecoration = "none";
        updateTileAppearance(id);
        updateTileTransform(id);
        convertedCount += 1;
        return;
      }

      if (tileEdgeDecoration(state) !== "none") {
        state.edgeDecoration = "none";
        updateTileAppearance(id);
        updateTileTransform(id);
        styleOnlyCount += 1;
      }
    });

    const changedCount = convertedCount + styleOnlyCount;

    if (changedCount === 0) {
      setStatus("No selected bubble-edge tiles could be converted to polygon edges.");
      return;
    }

    renderLatticeFills();
    hideSnapPreview();
    recordHistory();
    const convertedText = convertedCount > 0 ? ("Converted " + convertedCount + " tile" + (convertedCount === 1 ? "" : "s") + " to polygon edges.") : "";
    const styleText = styleOnlyCount > 0 ? (" Removed Bubble Style from " + styleOnlyCount + " tile" + (styleOnlyCount === 1 ? "" : "s") + ".") : "";
    setStatus((convertedText + styleText).trim());
  }

  function convertSelectedPolygonsToBubbleTiles() {
    const ids = selectedIds().filter(id => tiles[id]);

    if (ids.length === 0) {
      setStatus("Select a polygon tile to convert.");
      return;
    }

    let convertedCount = 0;

    ids.forEach(id => {
      const state = tiles[id];
      const definition = tileDefinitions[state.tileType];

      if (!definition || !Array.isArray(definition.vertices)) return;
      if (isBubbleConversionExcludedTileType(state.tileType)) return;
      if (Array.isArray(definition.bites) || definition.isConvertedBubbleTile) return;

      const convertedType = ensureConvertedBubbleTileDefinition(state.tileType);
      if (!convertedType) return;

      state.tileType = convertedType;
      state.edgeDecoration = "none";
      updateTileAppearance(id);
      updateTileTransform(id);
      convertedCount += 1;
    });

    if (convertedCount === 0) {
      setStatus("No selected polygon tiles could be converted.");
      return;
    }

    renderLatticeFills();
    hideSnapPreview();
    updateStylePreviewSelections();
    syncMenuControlsFromToolbar();
    recordHistory();
    noteGuidedTutorialEvent("polygon-converted-to-bubble");
    setStatus("Converted " + convertedCount + " polygon" + (convertedCount === 1 ? "" : "s") + " to bubble tile" + (convertedCount === 1 ? "" : "s") + ".");
  }


  function createTileIconSvg(tileType, className = "bubble-icon-svg") {
    const resolvedTileType = ensureDynamicTileDefinition(tileType) || tileType;
    const definition = tileDefinitions[resolvedTileType];

    if (!definition) return null;

    const iconSvg = document.createElementNS(SVG_NS, "svg");
    iconSvg.setAttribute("class", className + (definition.isFrame ? " frame-thumbnail-svg" : ""));
    if (definition.isPenroseKiteDart) iconSvg.classList.add("penrose-thumbnail-svg");

    if ((definition.isFrame || definition.isPenroseKiteDart) && Array.isArray(definition.vertices) && definition.vertices.length) {
      const xs = definition.vertices.map(v => v.x);
      const ys = definition.vertices.map(v => v.y);
      const minX = Math.min(...xs);
      const maxX = Math.max(...xs);
      const minY = Math.min(...ys);
      const maxY = Math.max(...ys);
      const pad = definition.isPenroseKiteDart ? Math.max(maxX - minX, maxY - minY) * 0.12 : 24;
      iconSvg.setAttribute("viewBox", `${minX - pad} ${minY - pad} ${(maxX - minX) + 2 * pad} ${(maxY - minY) + 2 * pad}`);
    } else {
      const viewRadius = Math.max(108, (definition.radius || 108) + 12);
      iconSvg.setAttribute("viewBox", `${-viewRadius} ${-viewRadius} ${2 * viewRadius} ${2 * viewRadius}`);
    }

    iconSvg.setAttribute("aria-hidden", "true");

    let shape;

    if (definition.path) {
      shape = document.createElementNS(SVG_NS, "path");
      shape.setAttribute("d", definition.path);
    } else {
      shape = document.createElementNS(SVG_NS, "polygon");
      shape.setAttribute("points", definition.points);
    }

    setShapePaint(shape, null, definition);

    if (definition.fillRule) {
      shape.setAttribute("fill-rule", definition.fillRule);
    }

    iconSvg.appendChild(shape);
    appendTileDecorations(iconSvg, definition);

    return iconSvg;
  }

