  function genericCollectionLayout(tileTypes, collectionName) {
    const maxRadius = tileTypes.reduce((maxRadiusSoFar, tileType) => {
      const resolvedTileType = ensureDynamicTileDefinition(tileType) || tileType;
      const definition = tileDefinitions[resolvedTileType];
      return Math.max(maxRadiusSoFar, definition && Number.isFinite(definition.radius) ? definition.radius : 80);
    }, 80);
    const spacing = Math.max(155, maxRadius * 2 + 34);
    const columns = collectionName.includes("hex") ? 7 : Math.min(4, tileTypes.length);
    const rows = Math.ceil(tileTypes.length / columns);
    const startX = -(columns - 1) * spacing / 2;
    const startY = -(rows - 1) * spacing / 2;

    return tileTypes.map((tileType, index) => ({
      tileType,
      x: startX + (index % columns) * spacing,
      y: startY + Math.floor(index / columns) * spacing
    }));
  }

  function addTileCollection(collectionName) {
    const tileTypes = tileCollections[collectionName];

    if (!tileTypes) return;

    const center = {
      x: viewBox.x + viewBox.width / 2,
      y: viewBox.y + viewBox.height / 2
    };

    const layout = paperCollectionLayout(collectionName) || genericCollectionLayout(tileTypes, collectionName);
    const newIds = [];

    placementHintsSuppressed = true;
    try {
      layout.forEach(item => {
        const resolvedTileType = tileDefinitions[item.tileType] ? item.tileType : ensureDynamicTileDefinition(item.tileType);
        if (!resolvedTileType) return;

        const newId = addPlacedTile(
          resolvedTileType,
          center.x + item.x,
          center.y + item.y,
          Number.isFinite(item.rotation) ? item.rotation : defaultRotationForTileType(resolvedTileType)
        );
        if (newId && tiles[newId]) {
          if (Number.isFinite(item.flipX)) tiles[newId].flipX = item.flipX;
          if (Number.isFinite(item.flipY)) tiles[newId].flipY = item.flipY;
          if (typeof item.fillColor === "string") tiles[newId].fillColor = item.fillColor;
          if (typeof item.edgeDecoration === "string") tiles[newId].edgeDecoration = item.edgeDecoration;
          updateTileAppearance(newId);
          updateTileTransform(newId);
        }
        newIds.push(newId);
      });
    } finally {
      placementHintsSuppressed = false;
    }

    selectMany(newIds);
    hideSnapPreview();
    recordHistory();
    recordRecentTraySet(collectionName);

    if (collectionName === "fourSided" || collectionName === "fiveSidedTrapezoid") {
      showTemporaryHint("Some tiles in this family are chiral. Their reflected versions were omitted from the collection; use Flip H or Flip V if you need the mirror image.", 9000);
    }

    setStatus("Added " + newIds.length + " tiles in the reference arrangement.");
  }

