  function activeGuidedTutorialSteps() {
    return guidedTutorialMode === "explore" ? guidedExploreTourSteps : guidedQuickTourSteps;
  }

  function noteGuidedTutorialEvent(eventName) {
    guidedTutorialEventCounts[eventName] = (guidedTutorialEventCounts[eventName] || 0) + 1;
    if (guidedTutorialMode === "explore" && guidedTutorialPanel && !guidedTutorialPanel.hidden) {
      updateGuidedTutorial();
    }
  }

  function guidedStepIsComplete(step) {
    if (!step) return false;
    if (typeof step.complete === "function") return Boolean(step.complete());
    if (step.event) return (guidedTutorialEventCounts[step.event] || 0) > guidedTutorialStepEventBaseline;
    return true;
  }

  function launchTutorialConfetti() {
    if (window.matchMedia && window.matchMedia("(prefers-reduced-motion: reduce)").matches) return;

    const overlay = document.createElement("div");
    overlay.className = "tutorial-confetti";
    overlay.setAttribute("aria-hidden", "true");
    const colors = ["#ffcf21", "#ff5a5f", "#33b5e5", "#5ac85a", "#9b6cff", "#ff8c42", "#f05cae"];
    const fragment = document.createDocumentFragment();

    [18, 50, 82].forEach(originPercent => {
      for (let index = 0; index < 44; index += 1) {
        const particle = document.createElement("i");
        const horizontalDirection = (Math.random() - 0.5) * 70;
        const width = 6 + Math.random() * 7;
        particle.style.left = originPercent + (Math.random() - 0.5) * 8 + "vw";
        particle.style.top = 38 + (Math.random() - 0.5) * 20 + "vh";
        particle.style.width = width + "px";
        particle.style.height = (width * (0.45 + Math.random() * 0.75)) + "px";
        particle.style.background = colors[Math.floor(Math.random() * colors.length)];
        particle.style.borderRadius = Math.random() > 0.72 ? "50%" : "2px";
        particle.style.setProperty("--confetti-mid-x", (horizontalDirection * 0.48) + "vw");
        particle.style.setProperty("--confetti-mid-y", (-20 - Math.random() * 28) + "vh");
        particle.style.setProperty("--confetti-end-x", horizontalDirection + "vw");
        particle.style.setProperty("--confetti-end-y", (50 + Math.random() * 45) + "vh");
        const spin = 540 + Math.random() * 900;
        particle.style.setProperty("--confetti-mid-spin", (spin * 0.48) + "deg");
        particle.style.setProperty("--confetti-spin", spin + "deg");
        particle.style.animationDelay = (Math.random() * 0.16) + "s";
        particle.style.animationDuration = (1.75 + Math.random() * 0.65) + "s";
        fragment.appendChild(particle);
      }
    });

    overlay.appendChild(fragment);
    document.body.appendChild(overlay);
    window.setTimeout(() => overlay.remove(), 2800);
  }

