  function bindScaleControls(slider, input) {
    if (!slider || !input) return;
    slider.addEventListener("pointerdown", event => {
      const currentValue = Number(slider.value);
      if (Math.abs(currentValue - 1) < 0.000001) return;
      const rect = slider.getBoundingClientRect();
      const thumbRadius = 7;
      const usableWidth = Math.max(1, rect.width - thumbRadius * 2);
      const onePosition = rect.left + thumbRadius + ((1 - Number(slider.min)) / (Number(slider.max) - Number(slider.min))) * usableWidth;
      if (Math.abs(event.clientX - onePosition) > 13) return;
      event.preventDefault();
      slider.value = "1";
      input.value = "1.0";
      setSelectionScale(1, true);
    });
    slider.addEventListener("input", () => {
      const factor = Number(slider.value);
      input.value = factor.toFixed(1);
      setSelectionScale(factor, false);
    });
    slider.addEventListener("change", () => {
      setSelectionScale(Number(slider.value), true);
    });
    input.addEventListener("keydown", event => {
      if (event.key !== "Enter") return;
      event.preventDefault();
      input.blur();
    });
    input.addEventListener("input", () => input.setCustomValidity(""));
    input.addEventListener("blur", () => {
      applyTypedScaleFactor(input);
    });
  }
  bindScaleControls(buttons.scaleFactorSlider, buttons.scaleFactorInput);
