  function renderRecentJsonFiles() {
    if (!recentJsonFilesElement) return;
    recentJsonFilesElement.innerHTML = "";

    if (recentJsonFiles.length === 0) {
      const empty = document.createElement("div");
      empty.className = "recent-json-empty";
      empty.textContent = "None opened or exported this session";
      recentJsonFilesElement.appendChild(empty);
      return;
    }

    recentJsonFiles.forEach(entry => {
      const button = document.createElement("button");
      button.type = "button";
      button.className = "recent-json-file";
      button.title = "Reopen " + entry.name;

      const icon = document.createElement("span");
      icon.className = "menu-item-icon";
      icon.setAttribute("aria-hidden", "true");
      icon.textContent = "↶";

      const label = document.createElement("span");
      label.className = "menu-label";
      label.textContent = entry.name;

      button.append(icon, label);
      button.addEventListener("click", () => {
        try {
          loadLayoutData(cloneLayoutData(entry.layout));
          recentJsonFiles = [entry, ...recentJsonFiles.filter(candidate => candidate !== entry)].slice(0, 5);
          renderRecentJsonFiles();
          recordHistory();
          setStatus("Reopened recent JSON file: " + entry.name + ".");
        } catch (error) {
          setStatus("Could not reopen recent JSON file.");
        }
      });

      recentJsonFilesElement.appendChild(button);
    });
  }

  function rememberRecentJsonFile(fileName, layoutData) {
    const name = String(fileName || "Untitled layout.json");
    recentJsonFiles = [
      { name, layout: cloneLayoutData(layoutData) },
      ...recentJsonFiles.filter(entry => entry.name !== name)
    ].slice(0, 5);
    renderRecentJsonFiles();
  }

