  function applyEdgeDecorationToSelection(decorationType, shouldRecord = true) {
    const allIds = selectedIds();

    if (allIds.length === 0) {
      if (shouldRecord) setStatus("Select a tile before changing Bubble Style.");
      return;
    }

    const normalized = ["none", "arc60", "puzzle", "spike", "zigzag"].includes(decorationType) ? decorationType : "none";
    const ids = allIds.filter(id => {
      const state = tiles[id];
      return state && isEdgeDecoratableDefinition(tileDefinitions[state.tileType]);
    });

    if (ids.length === 0) {
      if (shouldRecord) setStatus("Bubble Style applies to bubble tiles only; Einstein-family and soft/lens tiles are intentionally excluded.");
      return;
    }

    ids.forEach(id => {
      tiles[id].edgeDecoration = normalized;
      updateTileAppearance(id);
      updateTileTransform(id);
    });

    renderLatticeFills();
    updateStylePreviewSelections();

    if (shouldRecord) {
      recordHistory();
      noteGuidedTutorialEvent("bubble-style-applied");
      const skippedCount = allIds.length - ids.length;
      const skippedText = skippedCount > 0 ? ` Skipped ${skippedCount} non-bubble tile${skippedCount === 1 ? "" : "s"}.` : "";
      setStatus((normalized === "none" ? "Removed Bubble Style." : "Updated Bubble Style.") + skippedText);
    } else {
      setStatus("Previewing Bubble Style.");
    }
  }

